const https = require('https');
const http = require('http');

function fetchUrlMetadata(url, callback) {
  const urlObj = new URL(url);
  const client = urlObj.protocol === 'https:' ? https : http;
  
  const options = {
    method: 'GET',
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
    },
    timeout: 10000
  };

  const request = client.get(url, options, (response) => {
    if (response.statusCode >= 300 && response.statusCode < 400 && response.headers.location) {
      return fetchUrlMetadata(response.headers.location, callback);
    }

    if (response.statusCode !== 200) {
      return callback(new Error(`HTTP ${response.statusCode}`), null);
    }

    let html = '';
    
    response.on('data', (chunk) => {
      html += chunk.toString();
      if (html.length > 1048576) {
        request.destroy();
        return callback(new Error('Response too large'), null);
      }
    });

    response.on('end', () => {
      try {
        const metadata = parseMetadata(html);
        callback(null, metadata);
      } catch (error) {
        callback(error, null);
      }
    });
  });

  request.on('error', (error) => {
    callback(error, null);
  });

  request.on('timeout', () => {
    request.destroy();
    callback(new Error('Request timeout'), null);
  });
}

function parseMetadata(html) {
  const metadata = {
    title: null,
    description: null,
    ogTitle: null,
    ogDescription: null,
    ogImage: null,
    ogUrl: null,
    ogType: null,
    ogSiteName: null
  };

  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    metadata.title = decodeHtmlEntities(titleMatch[1].trim());
  }

  const descriptionMatch = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']+)["']/i);
  if (descriptionMatch) {
    metadata.description = decodeHtmlEntities(descriptionMatch[1].trim());
  }

  const ogTags = {
    'og:title': 'ogTitle',
    'og:description': 'ogDescription',
    'og:image': 'ogImage',
    'og:url': 'ogUrl',
    'og:type': 'ogType',
    'og:site_name': 'ogSiteName'
  };

  for (const [property, key] of Object.entries(ogTags)) {
    const regex = new RegExp(`<meta\\s+property=["']${property}["']\\s+content=["']([^"']+)["']`, 'i');
    const match = html.match(regex);
    if (match) {
      metadata[key] = decodeHtmlEntities(match[1].trim());
    }
  }

  return metadata;
}

function decodeHtmlEntities(text) {
  const entities = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&#x27;': "'",
    '&#x2F;': '/',
    '&#47;': '/'
  };

  return text.replace(/&[#\w]+;/g, (entity) => {
    return entities[entity] || entity;
  });
}

exports.getUrlMetadata = (req, res) => {
  res.set('Access-Control-Allow-Origin', '*');
  
  if (req.method === 'OPTIONS') {
    res.set('Access-Control-Allow-Methods', 'GET, POST');
    res.set('Access-Control-Allow-Headers', 'Content-Type');
    res.set('Access-Control-Max-Age', '3600');
    return res.status(204).send('');
  }

  const url = req.query.url || req.body?.url;

  if (!url) {
    return res.status(400).json({ error: 'URL parameter is required' });
  }

  try {
    new URL(url);
  } catch (error) {
    return res.status(400).json({ error: 'Invalid URL format' });
  }

  fetchUrlMetadata(url, (error, metadata) => {
    if (error) {
      return res.status(500).json({ error: error.message });
    }
    return res.status(200).json(metadata);
  });
};